import React, { useState } from 'react';
import SyntaxHighlighter from 'react-syntax-highlighter';
import { atomOneDark, atomOneLight } from 'react-syntax-highlighter/dist/esm/styles/hljs';

const MessageRenderer = ({ content, theme, contentType = 'general' }) => {
  const [copiedCode, setCopiedCode] = useState('');
  const codeStyle = theme === 'dark' ? atomOneDark : atomOneLight;

  const parseMarkdown = (text) => {
    const lines = text.split('\n');
    const elements = [];
    let currentCodeBlock = null;
    let codeLanguage = '';
    let codeContent = [];

    lines.forEach((line, index) => {
      // ✅ FIXED: Handle code blocks with properly terminated strings
      if (line.startsWith('```')) {
        if (currentCodeBlock === null) {
          // Starting code block
          codeLanguage = line.slice(3).trim() || 'text';
          currentCodeBlock = index;
          codeContent = [];
        } else {
          // Ending code block
          const codeText = codeContent.join('\n');
          elements.push(
            <div key={`code-${currentCodeBlock}`} className="code-block-container">
              <div className="code-header">
                <span className="code-language">{codeLanguage}</span>
                <button 
                  className="copy-code-btn"
                  onClick={() => copyToClipboard(codeText)}
                  title="Copy code"
                >
                  {copiedCode === codeText ? '✅' : '📋'}
                </button>
              </div>
              <SyntaxHighlighter
                language={codeLanguage}
                style={codeStyle}
                customStyle={{
                  margin: 0,
                  borderRadius: '0 0 8px 8px',
                  fontSize: '14px'
                }}
              >
                {codeText}
              </SyntaxHighlighter>
            </div>
          );
          currentCodeBlock = null;
          codeLanguage = '';
          codeContent = [];
        }
        return;
      }

      // Handle content inside code blocks
      if (currentCodeBlock !== null) {
        codeContent.push(line);
        return;
      }

      // Handle headers
      if (line.startsWith('## ')) {
        elements.push(
          <h3 key={`header-${index}`} className="message-header">
            {line.slice(3)}
          </h3>
        );
        return;
      }

      if (line.startsWith('### ')) {
        elements.push(
          <h4 key={`subheader-${index}`} className="message-subheader">
            {line.slice(4)}
          </h4>
        );
        return;
      }

      // Handle bold text
      if (line.includes('**')) {
        const boldFormatted = line.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
        elements.push(
          <p 
            key={`bold-${index}`} 
            className="message-text"
            dangerouslySetInnerHTML={{ __html: boldFormatted }}
          />
        );
        return;
      }

      // Handle bullet points
      if (line.trim().startsWith('- ')) {
        const bulletText = line.replace(/^-\s*/, '');
        elements.push(
          <div key={`bullet-${index}`} className="bullet-point">
            <span className="bullet-icon">•</span>
            <span className="bullet-text">{bulletText}</span>
          </div>
        );
        return;
      }

      // Handle regular paragraphs
      if (line.trim() !== '') {
        elements.push(
          <p key={`text-${index}`} className="message-text">
            {line}
          </p>
        );
      }
    });

    return elements;
  };

  const copyToClipboard = async (text) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopiedCode(text);
      // Reset after 2 seconds
      setTimeout(() => {
        setCopiedCode('');
      }, 2000);
    } catch (err) {
      console.error('Failed to copy code:', err);
    }
  };

  return (
    <div className={`message-content ${contentType}-content`}>
      {parseMarkdown(content)}
    </div>
  );
};

export default MessageRenderer;
